260	// ══════════════════════════════════════════════════════════════
261	// UpstreamMCPClient — MCP JSON-RPC proxy to upstream servers
262	// ══════════════════════════════════════════════════════════════
263	
264	export class UpstreamMCPClient {
265	  private readonly registry: UpstreamRegistry;
266	  private readonly failOpenState: FailOpenState;
267	  private readonly sessions = new Map<string, string>();
268	  private requestCounter = 0;
269	  private readonly activeConnections = new Map<string, number>();
270	  private readonly maxConcurrent: number;
271	
272	  constructor(registry: UpstreamRegistry) {
273	    this.registry = registry;
274	    this.failOpenState = registry.getFailOpenState();
275	    this.maxConcurrent = getMaxConcurrentUpstream();
276	  }
277	
278	  /** Fetch all tools from all healthy upstreams. */
279	  async listTools(): Promise<RawUpstreamTool[]> {
280	    const tools: RawUpstreamTool[] = [];
281	    const healthy = this.getHealthyUpstreams();
282	    const entries = this.registry.getAllUpstreams().filter((e) => healthy.includes(e.server.name));
283	
284	    const results = await Promise.allSettled(
285	      entries.map(async (entry) => {
286	        const rawTools = await this.fetchUpstreamTools(entry.server);
287	        return rawTools.map((t) => ({
288	          ...t,
289	          upstreamName: entry.server.name,
290	        }));
291	      }),
292	    );
293	
294	    for (const result of results) {
295	      if (result.status === 'fulfilled') {
296	        tools.push(...result.value);
297	      }
298	    }
299	
300	    return tools;
301	  }
302	
303	  /** Call a tool on a specific upstream server. */
304	  async callTool(
305	    upstreamName: string,
306	    toolName: string,
307	    args: Record<string, unknown>,
308	  ): Promise<UpstreamCallResult> {
309	    const entry = this.registry.getUpstream(upstreamName);
310	    if (!entry) {
311	      throw new Error(`Upstream "${upstreamName}" not found`);
312	    }
313	
314	    try {
315	      const result = await this.mcpRequest<UpstreamCallResult>(
316	        entry.server,
317	        'tools/call',
318	        { name: toolName, arguments: args },
319	      );
320	      recordUpstreamSuccess(this.failOpenState, upstreamName);
321	      return result;
322	    } catch (err) {
323	      recordUpstreamFailure(this.failOpenState, upstreamName);
324	      throw err;
325	    }
326	  }
327	
328	  /** Get list of healthy upstream names (circuit closed + last health check OK). */
329	  getHealthyUpstreams(): string[] {
330	    return this.registry.getAllUpstreams()
331	      .filter((e) => this.registry.isHealthy(e.server.name))
332	      .map((e) => e.server.name);
333	  }
334	
335	  /** Start periodic health checks on all upstreams. */
336	  startHealthChecks(): void {
337	    this.registry.startHealthChecks();
338	  }
339	
340	  /** Stop periodic health checks. */
341	  stopHealthChecks(): void {
342	    this.registry.stopHealthChecks();
343	  }
344	
345	  // ── Private: MCP JSON-RPC ────────────────────────────────
346	
347	  private async fetchUpstreamTools(server: UpstreamServer): Promise<Omit<RawUpstreamTool, 'upstreamName'>[]> {
348	    const result = await this.mcpRequest<{ tools: Array<{ name: string; description: string; inputSchema: Record<string, unknown> }> }>(
349	      server,
350	      'tools/list',
351	    );
352	    return (result.tools ?? []).map((t) => ({
353	      name: t.name,
354	      description: t.description ?? '',
355	      inputSchema: t.inputSchema ?? { type: 'object', properties: {} },
356	    }));
357	  }
358	
359	  private async mcpRequest<T>(
360	    server: UpstreamServer,
361	    method: string,
362	    params?: Record<string, unknown>,
363	  ): Promise<T> {
364	    // ── Concurrency gate ────────────────────────────────────
365	    const active = this.activeConnections.get(server.name) ?? 0;
366	    if (active >= this.maxConcurrent) {
367	      throw new Error(
368	        `Upstream "${server.name}" concurrency limit reached (${active}/${this.maxConcurrent})`,
369	      );
370	    }
371	    this.activeConnections.set(server.name, active + 1);
372	
373	    const id = ++this.requestCounter;
374	    const body = JSON.stringify({
375	      jsonrpc: '2.0',
376	      method,
377	      params: params ?? {},
378	      id,
379	    });
380	
381	    const headers: Record<string, string> = {
382	      'Content-Type': 'application/json',
383	      Accept: 'application/json',
384	    };
385	
386	    if (server.apiKey) {
387	      headers['Authorization'] = `Bearer ${server.apiKey}`;
388	    }
389	
390	    const sessionId = this.sessions.get(server.name);
391	    if (sessionId) {
392	      headers['Mcp-Session-Id'] = sessionId;
393	    }
394	
395	    const controller = new AbortController();
396	    const timeout = setTimeout(() => controller.abort(), MCP_CALL_TIMEOUT_MS);
397	
398	    try {
399	      const response = await fetch(server.url, {
400	        method: 'POST',
401	        headers,
402	        body,
403	        signal: controller.signal,
404	      });
405	
406	      // Cache session ID from response
407	      const newSessionId = response.headers.get('Mcp-Session-Id');
408	      if (newSessionId) {
409	        this.sessions.set(server.name, newSessionId);
410	      }
411	
412	      const contentType = response.headers.get('content-type') ?? '';
413	
414	      if (!response.ok) {
415	        const text = await response.text().catch(() => '');
416	        throw new Error(`Upstream ${server.name} returned HTTP ${response.status}: ${text.slice(0, 200)}`);
417	      }
418	
419	      // Handle non-JSON responses gracefully
420	      if (!contentType.includes('application/json') && !contentType.includes('text/plain')) {
421	        const text = await response.text();
422	        log.warn('Non-JSON upstream response', { server: server.name, method, contentType });
423	        // Try to parse as JSON anyway
424	        try {
425	          const data = JSON.parse(text);
426	          if (data.error) {
427	            throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
428	          }
429	          return data.result as T;
430	        } catch {
431	          // If it's not JSON at all, return as text content
432	          return { content: [{ type: 'text', text }] } as unknown as T;
433	        }
434	      }
435	
436	      const data = (await response.json()) as { error?: { message?: string }; result?: T };
437	
438	      if (data.error) {
439	        throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
440	      }
441	
442	      return data.result as T;
443	    } catch (err) {
444	      if (err instanceof DOMException && err.name === 'AbortError') {
445	        throw new Error(`Upstream ${server.name} timed out after ${MCP_CALL_TIMEOUT_MS}ms`);
446	      }
447	      throw err;
448	    } finally {
449	      clearTimeout(timeout);
450	      // Release concurrency slot
451	      const cur = this.activeConnections.get(server.name) ?? 1;
452	      if (cur <= 1) {
453	        this.activeConnections.delete(server.name);
454	      } else {
455	        this.activeConnections.set(server.name, cur - 1);
456	      }
457	    }
458	  }
459	}
